sql:
SELECT AVG(available_beds) AS average_available_beds
FROM hospital_resources
WHERE date = '2023-05-01';

SELECT total_ventilators
FROM hospital_resources
WHERE date = '2023-05-01';

SELECT hospital_name
FROM hospitals
ORDER BY hospital_name;

SELECT total_cases, active_cases
FROM covid_data
WHERE hospital_id = 0 AND date = '2023-05-01';

SELECT hospital_name
FROM hospitals
ORDER BY hospital_name;

SELECT icu_beds_occupied
FROM hospital_resources
WHERE hospital_id = 1 AND date = '1';

SELECT hospital_id, SUM(total_vaccinated) AS total_vaccinated
FROM vaccination_data
GROUP BY hospital_id;

SELECT total_vaccinated
FROM vaccination_data
WHERE hospital_id = 0 AND date = '0';

SELECT SUM(total_cases) AS total_reported_cases
FROM covid_data
WHERE date = '2023-05-01';

SELECT COUNT(DISTINCT hospital_id) AS hospital_count
FROM covid_data
WHERE date = '2023-05-01';

external_knowledge:
- ICU occupancy rate refers to the percentage of ICU beds currently occupied; 
- Ventilator occupancy rate refers to the percentage of ventilators currently in use; 
- Staff vaccination ratio refers to the percentage of hospital staff that have been vaccinated; 
- Previous vaccination rate refers to the vaccination rate of the previous date; 
- Vaccination rate change refers to the difference between the current vaccination rate and the previous vaccination rate.

